# CoAP Constants
COAP_VERSION = 1
COAP_TYPE_CON = 0  # Confirmable
COAP_TYPE_NON = 1  # Non-confirmable
COAP_TYPE_ACK = 2  # Acknowledgement
COAP_TYPE_RST = 3  # Reset

COAP_GET = 1
COAP_POST = 2
COAP_PUT = 3
COAP_DELETE = 4

COAP_RESPONSE_CONTENT = 69  # 2.05
